DROP TABLE IF EXISTS payment_audit_logs; DROP TABLE IF EXISTS payment_records; CREATE TABLE payment_records ( id BIGSERIAL PRIMARY KEY, employer_id BIGINT NOT NULL, provider_id BIGINT NOT NULL, target_year INTEGER NOT NULL, target_month INTEGER NOT NULL, amount NUMERIC(15, 2) NOT NULL, payment_date DATE NOT NULL, payment_method VARCHAR(50) NOT NULL, reference_number VARCHAR(100), notes TEXT, attachment_path VARCHAR(255), is_deleted BOOLEAN NOT NULL DEFAULT false, created_by VARCHAR(255), created_at TIMESTAMP WITHOUT TIME ZONE, updated_by VARCHAR(255), updated_at TIMESTAMP WITHOUT TIME ZONE ); CREATE INDEX idx_payment_records_employer_provider ON payment_records(employer_id, provider_id); CREATE INDEX idx_payment_records_year_month ON payment_records(target_year, target_month); CREATE TABLE payment_audit_logs ( id BIGSERIAL PRIMARY KEY, payment_id BIGINT NOT NULL, action_type VARCHAR(50) NOT NULL, old_amount NUMERIC(15, 2), new_amount NUMERIC(15, 2), reason TEXT, user_id VARCHAR(255) NOT NULL, timestamp TIMESTAMP WITHOUT TIME ZONE NOT NULL ); CREATE INDEX idx_payment_audit_logs_record_id ON payment_audit_logs(payment_id);
